const texto = $('Telegram Trigger').first().json.message?.text ?? '';
const senderId = String($('Telegram Trigger').first().json.message?.from?.id ?? '');
const senderUsername = $('Telegram Trigger').first().json.message?.from?.username ?? '';
const senderName = $('Telegram Trigger').first().json.message?.from?.first_name ?? 'Atendente';

const partes = texto.trim().split(/\s+/);
const comando = partes[0].toLowerCase();
const args = partes.slice(1);

return [{ json: { comando, args, senderId, senderUsername, senderName, textoCompleto: texto } }];

// ─────────────────────────────────────────────────────────────
// /pedido <userId> [entrada:Homus,QuibeCru,Tabule]
//         [esfihas:<n>] [quibes:<n>]
//         prato:Kafta,Charuto,Cordeiro
//         [talheres:sim|nao] [obs:<texto livre>]
//
// CARDÁPIO:
//   Entradas (opcional, máx 3):  Homus | QuibeCru | Tabule
//   Salgados (obrigatório preencher, pode ser 0):
//     esfihas:<n>   → número de Esfihas (R$8 cada)
//     quibes:<n>    → número de Quibes Assados (R$10 cada)
//   Pratos (obrigatório, ao menos 1): Kafta | Charuto | Cordeiro
//   talheres: sim | nao (padrão: nao)
//
// Exemplos:
//   /pedido 123456789 prato:Kafta,Charuto
//   /pedido 123456789 entrada:Homus,Tabule esfihas:2 quibes:1 prato:Kafta obs:sem pimenta
// ─────────────────────────────────────────────────────────────
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

const AJUDA = `📋 *Uso do /pedido:*

/pedido <telegramId> [entrada:...] [esfihas:n] [quibes:n] prato:... [talheres:sim|nao] [obs:...]

*Entradas* (opcional — escolha até 3):
  Homus | QuibeCru | Tabule
  Exemplo: entrada:Homus,Tabule

*Salgados* (preencha mesmo que seja 0):
  esfihas:<n>   ex: esfihas:2
  quibes:<n>    ex: quibes:0

*Pratos* (obrigatório, ao menos 1):
  Kafta | Charuto | Cordeiro
  Exemplo: prato:Kafta,Charuto

*Talheres* (opcional):
  talheres:sim | talheres:nao  (padrão: nao)

*Observação* (opcional):
  obs:sem pimenta

🔎 *Exemplos completos:*
/pedido 123456789 prato:Kafta
/pedido 123456789 entrada:Homus esfihas:2 quibes:0 prato:Kafta,Cordeiro talheres:sim obs:sem sal`;

if (args.length < 1) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Informe o Telegram ID do usuário.\n\n${AJUDA}` } }];
}

const targetUserId = String(args[0]);
const resto = args.slice(1).join(' ');

// ── parser de tokens chave:valor ──────────────────────────────
const tokenize = (str) => {
  const result = {};
  const regex = /(\w+):([^\s]+(?:\s+[^\w:]+)*)/g;
  let m;
  while ((m = regex.exec(str)) !== null) {
    result[m[1].toLowerCase()] = m[2].trim();
  }
  return result;
};
const tokens = tokenize(resto);

// ── Entradas ──────────────────────────────────────────────────
const entradasValidas = ['homus', 'quibecru', 'tabule'];
const entradasLabel   = { homus: 'Homus', quibecru: 'Quibe Cru', tabule: 'Tabule' };
const entradasVazias  = ['nda', 'nada'];
let entradas = [];
if (tokens.entrada) {
  const entradasVazias = ['nda', 'nada'];
  const candidatas = tokens.entrada.split(',').map(s => s.trim().toLowerCase());
  if (candidatas.every(e => entradasVazias.includes(e))) {
    entradas = [];
  } else {
    const invalidas = candidatas.filter(e => !entradasValidas.includes(e) && !entradasVazias.includes(e));
    if (invalidas.length > 0) {
      return [{ json: { sucesso: false, senderId,
        msg: `❌ Entrada inválida: ${invalidas.join(', ')}\nOpções: Homus | QuibeCru | Tabule | nada` } }];
    }
    entradas = candidatas.filter(e => !entradasVazias.includes(e)).map(e => entradasLabel[e]);
  }
}

// ── Salgados ──────────────────────────────────────────────────
const qtdEsfihas   = tokens.esfihas  !== undefined ? parseInt(tokens.esfihas)  : undefined;
const qtdQuibes    = tokens.quibes   !== undefined ? parseInt(tokens.quibes)   : undefined;

if (qtdEsfihas !== undefined && isNaN(qtdEsfihas)) {
  return [{ json: { sucesso: false, senderId, msg: '❌ esfihas deve ser um número. Ex: esfihas:2' } }];
}
if (qtdQuibes !== undefined && isNaN(qtdQuibes)) {
  return [{ json: { sucesso: false, senderId, msg: '❌ quibes deve ser um número. Ex: quibes:0' } }];
}

// ── Pratos (obrigatório ao menos 1) ──────────────────────────
const pratosValidos = ['kafta', 'charuto', 'cordeiro'];
const pratosLabel   = { kafta: 'Kafta', charuto: 'Charuto', cordeiro: 'Cordeiro' };

if (!tokens.prato) {
  return [{ json: { sucesso: false, senderId,
    msg: `❌ Pratos são obrigatórios.\n\nUse prato:Kafta, prato:Kafta,Charuto etc.\n\n${AJUDA}` } }];
}
const pratosCandidatos = tokens.prato.split(',').map(s => s.trim().toLowerCase());
const pratosInvalidos  = pratosCandidatos.filter(p => !pratosValidos.includes(p));
if (pratosInvalidos.length > 0) {
  return [{ json: { sucesso: false, senderId,
    msg: `❌ Prato inválido: ${pratosInvalidos.join(', ')}\nOpções: Kafta | Charuto | Cordeiro` } }];
}
const pratos = pratosCandidatos.map(p => pratosLabel[p]);

// ── Talheres ──────────────────────────────────────────────────
const talheresRaw = (tokens.talheres || 'nao').toLowerCase();
const talheres    = talheresRaw === 'sim' ? 'Sim' : 'Não';

// ── Observação ────────────────────────────────────────────────
const obs = tokens.obs || '';

// ── Persistir no storage ──────────────────────────────────────
if (!db.usuario) db.usuario = {};
if (!db.usuario[targetUserId]) {
  db.usuario[targetUserId] = {
    endereco: '', numeroPedidos: 0, pedidos: [],
    pagamento: 'nenhum', nomeCliente: 'nenhum', emailCliente: ''
  };
}

const pedidoAdmin = {
  'Entrada': entradas,
  'Gostaria de quantas Esfihas?':     qtdEsfihas  !== undefined ? qtdEsfihas  : 0,
  'Gostaria de quantos Quibes Assados?': qtdQuibes !== undefined ? qtdQuibes  : 0,
  'Pratos (selecione ao menos 1)':    pratos,
  'Gostaria de Talheres de Plástico ?': talheres,
  observacoes:       obs,
  criadoPorAtendente: senderId,
  _status: 'em preparo',
  criadoEm:          new Date().toISOString()
};

const num = db.usuario[targetUserId].numeroPedidos;
db.usuario[targetUserId].pedidos[num] = pedidoAdmin;
db.usuario[targetUserId].numeroPedidos++;

// ── Resumo para o atendente ───────────────────────────────────
let resumo = `✅ <b>Pedido #${num} criado!</b>\n\n`;
resumo += `👤 Usuário: <code>${targetUserId}</code>\n`;
if (entradas.length > 0) resumo += `🥗 Entradas: ${entradas.join(', ')}\n`;
if ((qtdEsfihas ?? 0) > 0) resumo += `🥙 Esfihas: ${qtdEsfihas}x\n`;
if ((qtdQuibes  ?? 0) > 0) resumo += `🍖 Quibes Assados: ${qtdQuibes}x\n`;
resumo += `🍽️ Pratos: ${pratos.join(', ')}\n`;
resumo += `🥄 Talheres: ${talheres}\n`;
if (obs) resumo += `📝 Obs: ${obs}\n`;
resumo += `📊 Status: preparando`;

return [{ json: { sucesso: true, senderId, msg: resumo } }];

// /pedido_consultar <userId>
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 1) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /pedido_consultar <telegramId>' } }];
}

const targetUserId = String(args[0]);
const usuario = db.usuario?.[targetUserId];

if (!usuario) {
