}

const data = args[0] || null;
const hora = args[1] || null;

let texto = '🍽️ Mesas disponíveis:\n\n';
db.mesas.forEach(mesa => {
  const ocupada = data && hora ? mesa.reservas.some(r => r.data === data && r.hora === hora) : false;
  const qtdReservas = mesa.reservas.length;
  const status = data && hora ? (ocupada ? '🔴 Ocupada' : '🟢 Livre') : `📅 ${qtdReservas} reserva(s)`;
  texto += `Mesa #${mesa.id} — ${mesa.tipo} (${mesa.capacidade} lugares) — ${status}\n`;
});

if (data && hora) {
  texto = `🍽️ Disponibilidade para ${data} às ${hora}:\n\n` + texto.replace('Mesas disponíveis:\n\n', '');
}

return [{ json: { sucesso: true, senderId, msg: texto } }];

// /mesa_reservar <userId> <mesaId> <data YYYY-MM-DD> <hora HH:MM> <pessoas>
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 5) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /mesa_reservar <telegramId> <mesaId> <data> <hora> <pessoas>\nExemplo: /mesa_reservar 123456789 3 2025-12-25 19:00 4' } }];
}

const [targetUserId, mesaIdStr, data, hora, pessoasStr] = args;
const mesaId = parseInt(mesaIdStr);
const pessoas = parseInt(pessoasStr);

if (!db.mesas) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Sistema de mesas não inicializado.' } }];
}

const mesa = db.mesas.find(m => m.id === mesaId);
if (!mesa) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Mesa #${mesaId} não encontrada.` } }];
}

const conflito = mesa.reservas.some(r => r.data === data && r.hora === hora);
if (conflito) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Mesa #${mesaId} já está reservada em ${data} às ${hora}.` } }];
}

mesa.reservas.push({ data, hora, pessoas, userId: targetUserId, criadoEm: new Date().toISOString(), criadoPorAtendente: senderId });

return [{ json: { sucesso: true, senderId, msg: `✅ Mesa #${mesaId} reservada!\n\n👤 Usuário: ${targetUserId}\n🍽️ Mesa: #${mesaId} — ${mesa.tipo} (${mesa.capacidade} lugares)\n📅 Data: ${data}\n🕐 Hora: ${hora}\n👥 Pessoas: ${pessoas}` } }];

// /mesa_cancelar <userId> <mesaId> <data> <hora>
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 4) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /mesa_cancelar <telegramId> <mesaId> <data> <hora>\nExemplo: /mesa_cancelar 123456789 3 2025-12-25 19:00' } }];
}

const [targetUserId, mesaIdStr, data, hora] = args;
const mesaId = parseInt(mesaIdStr);

if (!db.mesas) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Sistema de mesas não inicializado.' } }];
}

const mesa = db.mesas.find(m => m.id === mesaId);
if (!mesa) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Mesa #${mesaId} não encontrada.` } }];
}

const idx = mesa.reservas.findIndex(r => String(r.userId) === String(targetUserId) && r.data === data && r.hora === hora);
if (idx === -1) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Reserva não encontrada para o usuário ${targetUserId} na mesa #${mesaId} em ${data} às ${hora}.` } }];
}

mesa.reservas.splice(idx, 1);
return [{ json: { sucesso: true, senderId, msg: `🗑️ Reserva cancelada com sucesso!\n\n👤 Usuário: ${targetUserId}\n🍽️ Mesa: #${mesaId}\n📅 Data: ${data}\n🕐 Hora: ${hora}` } }];

