const bancoDados = $getWorkflowStaticData('global');
const userId = $('Telegram Trigger').first().json.message.chat.id;
const texto = ($('Telegram Trigger').first().json.message.text || '').trim();

const usuario = bancoDados.usuario?.[userId];

// Verifica se realmente está aguardando seleção
if (!usuario || !usuario.aguardandoSelecao) {
  return [{ json: { userId, sucesso: false, msg: '❌ Nenhuma seleção aguardada.' } }];
}

const numeroDigitado = parseInt(texto, 10); // 0 a 9 → índice 0..9 (pedido #1..#10)
// O usuário vê "Pedido #1" = índice 0, "Pedido #2" = índice 1, etc.
// Mas digitamos o número mostrado (1-based), então subtraímos 1
const indiceAbsoluto = usuario.indicesPedidosAtivos?.[numeroDigitado - 1];

if (indiceAbsoluto === undefined || indiceAbsoluto === null) {
  bancoDados.usuario[userId].aguardandoSelecao = false;
  delete bancoDados.usuario[userId].indicesPedidosAtivos;
  return [{ json: {
    userId,
    sucesso: false,
    msg: `❌ Número inválido. Nenhum pedido #${numeroDigitado} encontrado.\n\nUse o botão <b>🚚 Acompanhar Entrega</b> para tentar novamente.`
  }}];
}

const pedido = bancoDados.usuario[userId].pedidos[indiceAbsoluto];

// Validação: não pode marcar como entregue se status for cancelado ou pendente
const statusAtual = (pedido?._status || '').toLowerCase();
if (statusAtual === 'cancelado' || statusAtual === 'pendente') {
  bancoDados.usuario[userId].aguardandoSelecao = false;
  delete bancoDados.usuario[userId].indicesPedidosAtivos;
  return [{ json: {
    userId,
    sucesso: false,
    msg: `⚠️ Este pedido não pode ser marcado como entregue.\n\nStatus atual: <b>${pedido._status || 'Pendente'}</b>\n\nApenas pedidos em preparo ou a caminho podem ser marcados como entregues.`
  }}];
}

// Atualiza o status
bancoDados.usuario[userId].pedidos[indiceAbsoluto]._status = 'entregue';
bancoDados.usuario[userId].pedidos[indiceAbsoluto]._dataEntrega = new Date().toISOString();

// Limpa o estado de aguardo
bancoDados.usuario[userId].aguardandoSelecao = false;
delete bancoDados.usuario[userId].indicesPedidosAtivos;

const pratos = pedido['Pratos (selecione ao menos 1)']
  ? (Array.isArray(pedido['Pratos (selecione ao menos 1)'])
      ? pedido['Pratos (selecione ao menos 1)']
      : pedido['Pratos (selecione ao menos 1)'].split(',').map(s => s.trim())).filter(Boolean)
  : [];
const resumo = pratos.length ? pratos.join(', ') : 'Pedido';

return [{ json: {
  userId,
  sucesso: true,
  msg: `✅ <b>Pedido #${numeroDigitado} marcado como entregue!</b>\n\n📦 Itens: ${resumo}\n🕐 Confirmado em: ${new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' })}\n\nObrigado pela confirmação! 😊`
}}];
